import graphene
import psycopg2
from psycopg2.extras import RealDictCursor
from typing import List, Dict, Any

class SearchInput(graphene.InputObjectType):
    name = graphene.String()
    email = graphene.String()
    phone = graphene.String()
    status = graphene.String()

class SearchResult(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    email = graphene.String()
    phone = graphene.String()
    status = graphene.String()

class Query(graphene.ObjectType):
    search = graphene.List(
        SearchResult,
        input=graphene.Argument(SearchInput),
        limit=graphene.Int(default_value=100),
        offset=graphene.Int(default_value=0)
    )

    def resolve_search(self, info, input: SearchInput, limit: int, offset: int) -> List[SearchResult]:
        conn = psycopg2.connect(
            host="localhost",
            database="your_db",
            user="your_user",
            password="your_password"
        )
        cursor = conn.cursor(cursor_factory=RealDictCursor)
        
        try:
            where_conditions = []
            params = []
            
            if input.name:
                where_conditions.append("name ILIKE %s")
                params.append(f"%{input.name}%")
                
            if input.email:
                where_conditions.append("email ILIKE %s")
                params.append(f"%{input.email}%")
                
            if input.phone:
                where_conditions.append("phone ILIKE %s")
                params.append(f"%{input.phone}%")
                
            if input.status:
                where_conditions.append("status = %s")
                params.append(input.status)
            
            query = "SELECT id, name, email, phone, status FROM users"
            
            if where_conditions:
                query += " WHERE " + " AND ".join(where_conditions)
                
            query += " ORDER BY id LIMIT %s OFFSET %s"
            params.extend([limit, offset])
            
            cursor.execute(query, params)
            results = cursor.fetchall()
            
            return [SearchResult(**row) for row in results]
            
        finally:
            cursor.close()
            conn.close()

schema = graphene.Schema(query=Query)